#!/usr/bin/env bash
# One-time: register Tine's taskbar icon + .desktop entry on this machine.
# Run:  bash ~/research/tine-install-icon.sh   (optionally pass the binary path)
set -e
BIN="${1:-$HOME/research/tine}"
ICONS="$HOME/.local/share/icons/hicolor"
APPS="$HOME/.local/share/applications"
mkdir -p "$APPS" "$ICONS/256x256/apps"
# 256x256 PNG (the little green fork), embedded.
base64 -d > "$ICONS/256x256/apps/tine.png" <<'PNG'

PNG
cp "$ICONS/256x256/apps/tine.png" "$ICONS/256x256/apps/dev.tine.app.png"
# Desktop entry (named to match the app id; absolute Icon path so it always resolves).
cat > "$APPS/dev.tine.app.desktop" <<DESKTOP
[Desktop Entry]
Type=Application
Name=Tine
Comment=Fast Logseq-compatible outliner
Exec=$BIN %U
Icon=$ICONS/256x256/apps/tine.png
Terminal=false
Categories=Office;Utility;
StartupWMClass=tine
StartupNotify=true
DESKTOP
update-desktop-database "$APPS" 2>/dev/null || true
gtk-update-icon-cache -f "$ICONS" 2>/dev/null || true
echo "Installed Tine icon + desktop entry."
echo "Relaunch Tine (re-login if your compositor caches the taskbar)."
echo "If the icon still doesn't show, tell me Tine's app-id (it controls the match)."
